#include <bits/stdc++.h>
using namespace std;
long long n,m;
long long in[105];
long long ax[105];
long long a[105][25],b[105];
double c[25];
int main() {
	fill(in,in+105,10);
	fill(ax,ax+105,0);
	cin>>n>>m;
	for(int i=0; i<n; i++) {
		for(int j=0; j<m; j++) {
			cin>>a[i][j];
		}
	}
	for(int i=0; i<n; i++) {
		for(int j=0; j<m; j++) {
			if(a[i][j]<in[i]) {
				in[i]=a[i][j];
			}
			if(a[i][j]>ax[i]) {
				ax[i]=a[i][j];
			}

			b[i]+=a[i][j];
		}

	}
	for(int i=0; i<n; i++) {
		b[i]-=(in[i]+ax[i]);
	}
	
	for(int i=0; i<n; i++) {
		c[i]=1.0*b[i]/(m-2);
	}
	sort(c,c+n+1);
	cout<<fixed<<setprecision(2)<<c[n];
	return 0;
}
